14	use std::{
15	    str::FromStr,
16	    sync::{atomic::Ordering, Arc, Mutex, RwLock},
17	};
18	
19	use arc_swap::ArcSwapOption;
20	use uhlc::HLC;
21	use zenoh_config::{
22	    gateway::{GatewayPresetConf, GatewaySouthConf},
23	    ExpandedConfig,
24	};
25	use zenoh_protocol::core::{Bound, Region, WhatAmI, ZenohIdProto};
26	use zenoh_result::ZResult;
27	use zenoh_transport::{multicast::TransportMulticast, unicast::TransportUnicast, TransportPeer};
28	
29	pub use super::dispatcher::{pubsub::*, resource::*};
30	use super::{
31	    dispatcher::{
32	        face::Face,
33	        tables::{TablesData, TablesLock},
34	    },
35	    hat,
36	    interceptor::InterceptorsChain,
37	    runtime::Runtime,
38	};
39	use crate::net::{
40	    primitives::{DeMux, DummyPrimitives, EPrimitives, McastMux, Mux},
41	    routing::{
42	        dispatcher::{
43	            face::FaceStateBuilder,
44	            region::RegionMap,
45	            tables::{self, Tables},
46	        },
47	        hat::{DispatcherContext, HatTrait},
48	    },
49	};
50	
51	pub struct GatewayBuilder<'c> {
52	    config: &'c ExpandedConfig,
53	    hlc: Option<Arc<HLC>>,
54	    #[cfg(feature = "stats")]
55	    stats: Option<zenoh_stats::StatsRegistry>,
56	    #[cfg(test)]
57	    subregions: Option<Vec<Region>>,
58	    #[cfg(test)]
59	    disable_async_tree_computation: bool,
60	}
61	
62	impl<'conf> GatewayBuilder<'conf> {
63	    pub fn new(config: &'conf ExpandedConfig) -> GatewayBuilder<'conf> {
64	        Self {
65	            config,
66	            hlc: None,
67	            #[cfg(feature = "stats")]
68	            stats: None,
69	            #[cfg(test)]
70	            subregions: None,
71	            #[cfg(test)]
72	            disable_async_tree_computation: false,
73	        }
74	    }
75	
76	    pub fn hlc(mut self, hlc: Arc<HLC>) -> Self {
77	        self.hlc = Some(hlc);
78	        self
79	    }
80	
81	    #[cfg(test)]
82	    pub fn subregions(mut self, subregions: Vec<Region>) -> Self {
83	        self.subregions.replace(subregions);
84	        self
85	    }
86	
87	    #[cfg(feature = "stats")]
88	    pub fn stats(mut self, stats: zenoh_stats::StatsRegistry) -> Self {
89	        self.stats = Some(stats);
90	        self
91	    }
92	
93	    #[cfg(test)]
94	    pub fn disable_async_tree_computation(mut self, value: bool) -> Self {
95	        self.disable_async_tree_computation = value;
96	        self
97	    }
98	
99	    pub fn build(self) -> ZResult<Gateway> {
100	        let mode = self.config.mode();
101	
102	        let mut regions = vec![Region::North];
103	
104	        let mut set_regions_with_config = || {
105	            match self.config.gateway.south.clone().unwrap_or_default() {
106	                GatewaySouthConf::Preset(GatewayPresetConf::Auto) => match mode {
107	                    WhatAmI::Router => {
108	                        for mode in [WhatAmI::Client, WhatAmI::Peer] {
109	                            regions.push(Region::default_south(mode));
110	                        }
111	                    }
112	                    WhatAmI::Peer => {
113	                        regions.push(Region::default_south(WhatAmI::Client));
114	                    }
115	                    WhatAmI::Client => {}
116	                },
117	                GatewaySouthConf::Custom(subregions) => {
118	                    for (id, _) in subregions.iter().enumerate() {
119	                        // NOTE(regions): we create three hats per subregion.
120	                        // If memory usage is an issue, we should create then lazily.
121	                        for mode in [WhatAmI::Client, WhatAmI::Peer, WhatAmI::Router] {
122	                            regions.push(Region::South { id, mode });
123	                        }
124	                    }
125	                }
126	            }
127	
128	            regions.push(Region::Local);
129	        };
130	
131	        #[cfg(not(test))]
132	        set_regions_with_config();
133	
134	        #[cfg(test)]
135	        if let Some(subregions) = self.subregions {
136	            regions.extend_from_slice(&subregions);
137	        } else {
138	            set_regions_with_config()
139	        }
140	
141	        let zid = ZenohIdProto::from(self.config.id());
142	
143	        #[cfg(feature = "stats")]
144	        let stats = self
145	            .stats
146	            .unwrap_or_else(|| zenoh_stats::StatsRegistry::new(zid, mode, &*crate::LONG_VERSION));
147	
148	        tracing::debug!(?regions);
149	
150	        let hats = regions
151	            .iter()
152	            .copied()
153	            .map(|region| -> (Region, Box<dyn HatTrait + Send + Sync>) {
154	                (
155	                    region,
156	                    match (region.bound(), region.mode().unwrap_or(mode)) {
157	                        (Bound::North, WhatAmI::Client) => Box::new(hat::client::Hat::new(region)),
158	                        (Bound::South, WhatAmI::Client) => Box::new(hat::broker::Hat::new(region)),
159	                        (_, WhatAmI::Peer) => Box::new(hat::peer::Hat::new(region)),
160	                        (_, WhatAmI::Router) => {
161	                            #[cfg(test)]
162	                            {
163	                                let mut hat = hat::router::Hat::new(region);
164	                                hat.set_disable_async_tree_computation(
165	                                    self.disable_async_tree_computation,
166	                                );
167	                                Box::new(hat)
168	                            }
169	
170	                            #[cfg(not(test))]
171	                            Box::new(hat::router::Hat::new(region))
172	                        }
173	                    },
174	                )
175	            })
176	            .collect::<RegionMap<_>>();
177	
178	        let data = TablesData::new(
179	            zid,
180	            self.hlc,
181	            self.config,
182	            regions
183	                .iter()
184	                .copied()
185	                .map(|b| (b, tables::HatTablesData::new()))
186	                .collect(),
187	            #[cfg(feature = "stats")]
188	            stats,
189	        )?;
190	
191	        Ok(Gateway {
192	            tables: Arc::new(TablesLock {
193	                tables: RwLock::new(Tables { data, hats }),
194	                ctrl_lock: Mutex::new(()),
195	                queries_lock: RwLock::new(()),
196	            }),
197	        })
198	    }
199	}
200	
201	pub struct Gateway {
202	    // whatami: WhatAmI,
203	    pub tables: Arc<TablesLock>,
204	}
205	
206	impl Gateway {
207	    pub fn init_hats(&mut self, runtime: Runtime) -> ZResult<()> {
208	        let _ctrl_lock = zlock!(self.tables.ctrl_lock);
209	        let mut wtables = zwrite!(self.tables.tables);
210	        let tables = &mut *wtables;
211	        tables.data.runtime = Some(Runtime::downgrade(&runtime));
212	
213	        for (_, hat) in tables.hats.iter_mut() {
214	            hat.init(&mut tables.data, runtime.clone())?
215	        }
216	
217	        Ok(())
218	    }
219	
220	    pub(crate) fn new_session(&self, primitives: Arc<dyn EPrimitives + Send + Sync>) -> Arc<Face> {
221	        let ctrl_lock = zlock!(self.tables.ctrl_lock);
222	        let mut wtables = zwrite!(self.tables.tables);
223	        let tables = &mut *wtables;
224	
225	        let newface = Arc::new(
226	            FaceStateBuilder::new(
227	                tables.data.new_face_id(),
228	                tables.data.zid,
229	                Region::Local,
230	                Bound::North,
231	                primitives.clone(),
232	                tables.hats.map_ref(|hat| hat.new_face()),
233	            )
234	            .whatami(WhatAmI::Client)
235	            .local(true)
236	            .build(),
237	        );
238	        tables.data.faces.insert(newface.id, newface.clone());
239	        tracing::debug!("New {}", newface);
240	
241	        let mut face = Face {
242	            tables: self.tables.clone(),
243	            state: newface,
244	        };
245	        tables.hats[face.state.region]
246	            .new_local_face(
247	                DispatcherContext {
248	                    tables_lock: &face.tables,
249	                    tables: &mut tables.data,
250	                    src_face: &mut face.state,
251	                    send_declare: &mut |_, _| {
252	                        unreachable!("no declarations should be pushed to new session faces")
253	                    },
254	                },
255	                &self.tables,
256	            )
257	            .unwrap();
258	        drop(wtables);
259	        drop(ctrl_lock);
260	
261	        Arc::new(face)
262	    }
263	
264	    pub fn new_transport_unicast(
265	        &self,
266	        transport: TransportUnicast,
267	        region: Region,
268	        remote_bound: Bound,
269	    ) -> ZResult<Arc<DeMux>> {
270	        let ctrl_lock = zlock!(self.tables.ctrl_lock);
271	        let mut wtables = zwrite!(self.tables.tables);
272	        let tables = &mut *wtables;
273	
274	        let whatami = transport.get_whatami()?;
275	        let fid = tables.data.new_face_id();
276	        let zid = transport.get_zid()?;
277	        let this_zid = tables.data.zid;
278	
279	        let ingress = Arc::new(ArcSwapOption::new(InterceptorsChain::empty().into()));
280	        let mux = Arc::new(Mux::new(transport.clone(), InterceptorsChain::empty()));
281	
282	        #[cfg(feature = "stats")]
283	        let stats = transport.get_stats().ok();
284	
285	        let newface = tables
286	            .data
287	            .faces
288	            .entry(fid)
289	            .or_insert_with(|| {
290	                let builder = FaceStateBuilder::new(
291	                    fid,
292	                    zid,
293	                    region,
294	                    remote_bound,
295	                    mux.clone(),
296	                    tables.hats.map_ref(|hat| hat.new_face()),
297	                )
298	                .whatami(whatami)
299	                .ingress_interceptors(ingress.clone());
300	
301	                #[cfg(feature = "stats")]
302	                let builder = {
303	                    if let Some(stats) = stats {
304	                        builder.stats(stats)
305	                    } else {
306	                        builder
307	                    }
308	                };
309	
310	                Arc::new(builder.build())
311	            })
312	            .clone();
313	
314	        newface.set_interceptors_from_factories(
315	            &tables.data.interceptors,
316	            tables.data.next_interceptor_version.load(Ordering::SeqCst),
317	        );
318	        tracing::debug!("New {}", newface);
319	
320	        let mut face = Face {
321	            tables: self.tables.clone(),
322	            state: newface,
323	        };
324	
325	        let _ = mux.face.set(Face::downgrade(&face));
326	
327	        let mut declares = vec![];
328	        let (owner_hat, other_hats) = tables
329	            .hats
330	            .partition_mut(&region)
331	            .expect("computed transport region should have a corresponding hat");
332	        let ctx = DispatcherContext {
333	            tables_lock: &face.tables,
334	            tables: &mut tables.data,
335	            src_face: &mut face.state,
336	            send_declare: &mut |p, m| declares.push((p.clone(), m)),
337	        };
338	        owner_hat.new_transport_unicast_face(
339	            ctx,
340	            &transport,
341	            other_hats.map(|hat| &**hat as &dyn HatTrait),
342	        )?;
343	        drop(wtables);
344	        drop(ctrl_lock);
345	        for (p, m) in declares {
346	            m.with_mut(|m| p.send_declare(m));
347	        }
348	
349	        Ok(Arc::new(DeMux::new(
350	            face,
351	            Some(transport),
352	            ingress,
353	            this_zid,
354	        )))
355	    }
356	
357	    pub fn new_transport_multicast(
358	        &self,
359	        transport: TransportMulticast,
360	        region: Region,
361	    ) -> ZResult<()> {
362	        let _ctrl_lock = zlock!(self.tables.ctrl_lock);
363	        let mut wtables = zwrite!(self.tables.tables);
364	        let tables = &mut *wtables;
365	
366	        let fid = tables.data.new_face_id();
367	        let mux = Arc::new(McastMux::new(transport.clone(), InterceptorsChain::empty()));
368	
369	        #[cfg(feature = "stats")]
370	        let stats = transport.get_stats().ok();
371	
372	        let builder = FaceStateBuilder::new(
373	            fid,
374	            ZenohIdProto::from_str("1").unwrap(),
375	            region,
376	            Bound::default(), // HACK(regions): this is a placeholder
377	            mux.clone(),
378	            tables.hats.map_ref(|hat| hat.new_face()),
379	        )
380	        .multicast_group(transport);
381	
382	        #[cfg(feature = "stats")]
383	        let builder = {
384	            if let Some(stats) = stats {
385	                builder.stats(stats)
386	            } else {
387	                builder
388	            }
389	        };
390	
391	        let face = Arc::new(builder.build());
392	
393	        face.set_interceptors_from_factories(
394	            &tables.data.interceptors,
395	            tables.data.next_interceptor_version.load(Ordering::SeqCst),
396	        );
397	        let _ = mux.face.set(Face {
398	            state: face.clone(),
399	            tables: self.tables.clone(),
400	        });
401	
402	        tables.data.hats[region].mcast_groups.push(face);
403	
404	        tables.hats[region].disable_all_routes(&mut tables.data);
405	
406	        Ok(())
407	    }
408	
409	    pub fn new_peer_multicast(
410	        &self,
411	        transport: TransportMulticast,
412	        peer: TransportPeer,
413	        region: Region,
414	        remote_bound: Bound,
415	    ) -> ZResult<Arc<DeMux>> {
416	        let _ctrl_lock = zlock!(self.tables.ctrl_lock);
417	        let mut wtables = zwrite!(self.tables.tables);
418	        let tables = &mut *wtables;
419	
420	        let fid = tables.data.new_face_id();
421	        let interceptor = Arc::new(ArcSwapOption::new(InterceptorsChain::empty().into()));
422	        let this_zid = tables.data.zid;
423	
424	        #[cfg(feature = "stats")]
425	        let stats = transport.get_stats().ok();
426	
427	        let builder = FaceStateBuilder::new(
428	            fid,
429	            peer.zid,
430	            region,
431	            remote_bound,
432	            Arc::new(DummyPrimitives),
433	            tables.hats.map_ref(|hat| hat.new_face()),
434	        )
435	        .multicast_group(transport)
436	        .ingress_interceptors(interceptor.clone());
437	
438	        #[cfg(feature = "stats")]
439	        let builder = {
440	            if let Some(stats) = stats {
441	                builder.stats(stats)
442	            } else {
443	                builder
444	            }
445	        };
446	
447	        let face = Arc::new(builder.build());
448	
449	        face.set_interceptors_from_factories(
450	            &tables.data.interceptors,
451	            tables.data.next_interceptor_version.load(Ordering::SeqCst),
452	        );
453	
454	        tables.data.hats[region].mcast_faces.push(face.clone());
455	
456	        tables.hats[region].disable_all_routes(&mut tables.data);
457	
458	        Ok(Arc::new(DeMux::new(
459	            Face {
460	                tables: self.tables.clone(),
461	                state: face,
462	            },
463	            None,
464	            interceptor,
465	            this_zid,
466	        )))
467	    }
468	}
469

