46	pub(crate) struct RoutingExpr<'a> {
47	    prefix: &'a Arc<Resource>,
48	    suffix: &'a str,
49	    resource: OnceCell<Option<&'a Arc<Resource>>>,
50	    key_expr: OnceCell<Option<Cow<'a, keyexpr>>>,
51	}
52	
53	impl Debug for RoutingExpr<'_> {
54	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
55	        write!(f, "{:?}{}", self.prefix, self.suffix)
56	    }
57	}
58	
59	impl<'a> RoutingExpr<'a> {
60	    #[inline]
61	    pub(crate) fn new(prefix: &'a Arc<Resource>, suffix: &'a str) -> Self {
62	        let resource = if suffix.is_empty() {
63	            Some(prefix).into()
64	        } else {
65	            OnceCell::new()
66	        };
67	        RoutingExpr {
68	            prefix,
69	            suffix,
70	            resource,
71	            key_expr: OnceCell::new(),
72	        }
73	    }
74	
75	    pub(crate) fn resource(&self) -> Option<&'a Arc<Resource>> {
76	        *self
77	            .resource
78	            .get_or_init(|| Resource::get_resource_ref(self.prefix, self.suffix))
79	    }
80	
81	    fn compute_key_expr(&self) -> Option<Cow<'a, keyexpr>> {
82	        let full_expr = match self.resource().as_ref() {
83	            Some(res) => res
84	                .keyexpr()
85	                .ok_or_else(|| keyexpr::new("").unwrap_err())
86	                .map(Cow::Borrowed),
87	            None => [self.prefix.expr(), self.suffix]
88	                .concat()
89	                .try_into()
90	                .map(Cow::Owned),
91	        };
92	        if let Err(e) = &full_expr {
93	            tracing::warn!("Invalid KE reached the system: {}", e);
94	        }
95	        full_expr.ok()
96	    }
97	
98	    pub(crate) fn key_expr(&self) -> Option<&keyexpr> {
99	        self.key_expr
100	            .get_or_init(|| self.compute_key_expr())
101	            .as_deref()
102	    }
103	
104	    pub(crate) fn get_best_key(&self, sid: usize) -> WireExpr<'a> {
105	        match self.resource() {
106	            Some(res) => res.get_best_key("", sid),
107	            None => self.prefix.get_best_key(self.suffix, sid),
108	        }
109	    }
110	
111	    #[cfg(feature = "stats")]
112	    pub(crate) fn is_admin(&self) -> bool {
113	        let admin_prefix = "@/";
114	        if self.prefix.parent.is_none() {
115	            self.suffix.starts_with(admin_prefix)
116	        } else {
117	            self.prefix.expr().starts_with(admin_prefix)
118	        }
119	    }
120	}
