271	/// Gateway state.
272	///
273	/// In order to mutably borrow [`Tables::data`] and [`Tables::hats`] at the same time given an
274	/// acquired guard from [`TablesLock::tables`], one needs to first dereference the guard into [`Tables`]:
275	///
276	/// ```rust,ignore
277	/// fn borrow_hats_and_data(tables_lock: &TablesLock) {
278	///     let mut guard = tables_lock.tables.write().unwrap();
279	///
280	///     // NOTE(regions): The following doesn't compile due to E0499:
281	///     // let hats = &mut guard.hats;
282	///     // let tables_data = &mut guard.data;
283	///     // drop((hats, tables_data));
284	///
285	///     let tables = &mut *guard;
286	///     let hats = &mut tables.hats;
287	///     let tables_data = &mut tables.data;
288	///     drop((hats, tables_data));
289	/// }
290	/// ```
291	pub struct Tables {
292	    pub data: TablesData,
293	    pub hats: RegionMap<Box<dyn HatTrait + Send + Sync>>,
294	}
295	
296	impl Tables {
297	    pub(crate) fn sourced_subscribers(&self) -> HashMap<Arc<Resource>, Sources> {
298	        self.hats
299	            .values()
300	            .flat_map(|hat| {
301	                self.add_north_source(&hat.region(), hat.sourced_subscribers(&self.data))
302	            })
303	            .fold(HashMap::new(), |mut acc, (res, src)| {
304	                acc.entry(res.clone())
305	                    .and_modify(|s| s.extend(&src))
306	                    .or_insert(src);
307	                acc
308	            })
309	    }
310	
311	    pub(crate) fn sourced_queryables(&self) -> HashMap<Arc<Resource>, Sources> {
312	        self.hats
313	            .values()
314	            .flat_map(|hat| {
315	                self.add_north_source(&hat.region(), hat.sourced_queryables(&self.data))
316	            })
317	            .fold(HashMap::new(), |mut acc, (res, src)| {
318	                acc.entry(res.clone())
319	                    .and_modify(|s| s.extend(&src))
320	                    .or_insert(src);
321	                acc
322	            })
323	    }
324	
