342	        mut entities: HashMap<Arc<Resource>, Sources>,
343	    ) -> HashMap<Arc<Resource>, Sources> {
344	        if region.bound().is_south() {
345	            let north_source =
346	                Sources::empty().with_mode([self.data.zid], self.hats[Region::North].mode());
347	            for entity in entities.values_mut().filter(|e| !e.is_empty()) {
348	                entity.extend(&north_source);
349	            }
