391	/// Inter-region filter.
392	///
393	/// We reject messages in two scenarios:
394	/// 1. The source node is a gateway.
395	/// 2. We are not the primary gateway.
396	///
397	/// # South-to-North
398	///
399	/// ```text
400	///   fwd_zid = Some(F)                        fwd_zid = None
401	///   ┌───────────────────┐                    ┌───────────────────┐
402	///   │                   │                    │                   │
403	///   │     G   ...  G'   │                    │     G  ...  G'    │
404	///   └─────/─────────\───┘                    └─────/─────────\───┘
405	///   ┌────/───────────\──┐                    ┌────/───────────\──┐
406	///   │   G     ...    G' │                    │   G     ...    G' │
407	///   │    \          /   │                    │                   │
408	///   │     F ─ ─ ─ ─     │  fwd (south)       │     F             │  fwd (south)
409	///   │     |             │                    │                   │
410	///   │     S             │  src (south)       │     S             │  src (south)
411	///   └───────────────────┘                    └───────────────────┘
412	///
413	///   gwys = gateways known to F                gwys = all region gateways
414	/// ```
415	///
416	/// # North-to-South
417	///
418	/// ```text
419	///   dst_zid = Some(D)                        dst_zid = None
420	///   ┌───────────────────┐                    ┌───────────────────┐
421	///   │       S           │  src               │       S           │  src
422	///   │                   │                    │                   │
423	///   │     G  ...  G'    │                    │     G   ...   G'  │
424	///   └─────/─────────\───┘                    └─────/─────────\───┘
425	///   ┌────/───────────\──┐                    ┌────/───────────\──┐
426	///   │   G0    ...    G1 │                    │   G     ...    G' │
427	///   │    \          /   │                    │                   │
428	///   │     D ─ ─ ─ ─     │  dst (south)       │     D             │ dst (south)
429	///   └───────────────────┘                    └───────────────────┘
430	///
431	///   gwys = gateways known to D                gwys = all region gateways
432	/// ```
433	///
434	/// In both cases: `primary = max(gwys)`, allow iff `self.zid == primary`.
435	#[derive(Debug, Clone, Copy)]
436	pub(crate) struct InterRegionFilter<'a> {
437	    /// Source region.
438	    pub src: &'a Region,
439	    /// Destination region.
440	    pub dst: &'a Region,
441	    /// ZID of the source node which is potentially different than [`InterRegionFilter::fwd_zid`] in
442	    /// linkstate.
443	    pub src_zid: Option<&'a ZenohIdProto>,
444	    /// ZID of the source face.
445	    pub fwd_zid: Option<&'a ZenohIdProto>,
446	    /// ZID of the destination node.
447	    pub dst_zid: Option<&'a ZenohIdProto>,
448	}
449	
450	impl InterRegionFilter<'_> {
451	    /// Returns `false` if a `Push` or `Request` should be filtered out.
452	    pub(crate) fn resolve(&self, tables: &Tables) -> bool {
453	        // NOTE(regions): we initialize the tracing span iff the TRACE level is enabled and we use
454	        // aux to trace the filtering event.
455	
456	        let _span = tracing::enabled!(tracing::Level::TRACE).then(|| {
457	            tracing::trace_span!(
458	                "inter_region_filter",
459	                src = %self.src,
460	                dst = %self.dst,
461	                src_zid = ?self.src_zid.map(|zid| zid.short()),
462	                fwd_zid = ?self.fwd_zid.map(|zid| zid.short()),
463	                dst_zid = ?self.dst_zid.map(|zid| zid.short()),
464	            )
465	            .entered()
466	        });
467	
468	        let ret = aux(self, tables);
469	        tracing::trace!(return = ret);
470	        return ret;
471	
472	        fn aux(this: &InterRegionFilter<'_>, tables: &Tables) -> bool {
473	            if this.src.bound() == this.dst.bound() {
474	                // NOTE(regions): only messages traveling downstream/upstream need filtering, i.e. in
475	                // the presence of multiple region gateways.
476	                return true;
477	            }
478	
479	            let gwys = match this.src.bound() {
480	                Bound::North => this
481	                    .dst_zid
482	                    .map(|dst_zid| tables.hats[this.dst].gateways_of(&tables.data, dst_zid))
483	                    .unwrap_or_else(|| tables.hats[this.dst].gateways(&tables.data)),
484	                // NOTE(regions): in this case, we cannot have a link with `src_zid` if it were also a
485	                // gateway so we check the "forwarder's" zid. This works for routers and peers alike.
486	                // See `multiple_gateways_data_routing_r2r_upstream_gateway_source` in
487	                // net::tests::regions::routing.
488	                Bound::South => this
489	                    .fwd_zid
490	                    .map(|fwd_zid| tables.hats[this.src].gateways_of(&tables.data, fwd_zid))
491	                    .unwrap_or_else(|| tables.hats[this.src].gateways(&tables.data)),
492	            };
493	
494	            let Some(gwys) = gwys.filter(|g| !g.is_empty()) else {
495	                return true;
496	            };
497	
498	            let Some(src_zid) = this.src_zid else {
499	                bug!("Unknown source ZID");
500	                return true;
501	            };
502	
503	            // HACK(regions): this has the effect of filtering out messages originating from a router
504	            // subregion from being re-routed to the north (router) region. As the router linkstate
505	            // protocol is unimplemented, our hand is forced.
506	            if gwys.contains(src_zid) {
507	                return false;
508	            }
509	
510	            // SAFETY: gwys is guaranteed non-empty by the filter above.
511	            let primary = gwys.iter().max().unwrap();
512	
513	            &tables.data.zid == primary
514	        }
515	    }
516	}
517	
518	impl Debug for Tables {
519	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
520	        f.debug_struct("Tables").finish()
521	    }
522	}
523	
524	impl TablesLock {
525	    #[allow(dead_code)]
526	    pub(crate) fn update_config(&self, config: &Config) -> ZResult<()> {
527	        let mut tables = zwrite!(self.tables);
528	        #[cfg(feature = "stats")]
529	        {
530	            let tables = &mut *tables;
531	            tables.data.stats.update_keys(
532	                &mut tables.data.stats_keys,
533	                config.stats.filters().iter().map(|k| &*k.key),
534	            );
535	        }
536	        tables.data.interceptors = interceptor_factories(config)?;
537	        drop(tables);
538	        let tables = zread!(self.tables);
539	        let version = tables
540	            .data
541	            .next_interceptor_version
542	            .fetch_add(1, Ordering::SeqCst);
543	        tables.data.faces.values().for_each(|face| {
544	            face.set_interceptors_from_factories(&tables.data.interceptors, version + 1);
545	        });
546	        Ok(())
547	    }
548	}
