302	    pub(crate) fn set_interceptors_from_factories(
303	        &self,
304	        factories: &[InterceptorFactory],
305	        version: usize,
306	    ) {
307	        if let Some(mux) = self.primitives.as_any().downcast_ref::<Mux>() {
308	            let (ingress, egress): (Vec<_>, Vec<_>) = factories
309	                .iter()
310	                .map(|itor| itor.new_transport_unicast(&mux.handler))
311	                .unzip();
312	            let (ingress, egress) = (
313	                InterceptorsChain::new(ingress.into_iter().flatten().collect::<Vec<_>>(), version),
314	                InterceptorsChain::new(egress.into_iter().flatten().collect::<Vec<_>>(), version),
315	            );
316	            mux.interceptor
317	                .store((!egress.is_empty()).then(|| egress.into()));
318	            self.in_interceptors
319	                .as_ref()
320	                .expect("face in_interceptors should not be None when primitives are Mux")
321	                .store(ingress.into());
322	        } else if let Some(mux) = self.primitives.as_any().downcast_ref::<McastMux>() {
323	            let interceptor = InterceptorsChain::new(
324	                factories
325	                    .iter()
326	                    .filter_map(|itor| itor.new_transport_multicast(&mux.handler))
327	                    .collect::<Vec<EgressInterceptor>>(),
328	                version,
329	            );
330	            mux.interceptor.store(interceptor.into());
331	            debug_assert!(self.in_interceptors.is_none());
332	        } else if let Some(transport) = &self.mcast_group {
333	            let interceptor = InterceptorsChain::new(
334	                factories
335	                    .iter()
336	                    .filter_map(|itor| itor.new_peer_multicast(transport))
337	                    .collect::<Vec<IngressInterceptor>>(),
338	                version,
339	            );
340	            self.in_interceptors
341	                .as_ref()
342	                .expect("face in_interceptors should not be None when mcast_group is set")
343	                .store(interceptor.into());
344	        }
345	    }
