411	    /// Resolves `expr` to a [`Resource`] (creating it if needed), acquires the [`Tables`] write
412	    /// lock, then calls `f(tables, resource)`.
413	    ///
414	    /// Returns early without calling `f` if the wire-expr scope is unknown.
415	    /// Use this for **declare** operations where the resource must exist after the call.
416	    pub(crate) fn with_mapped_expr<F>(&self, expr: &WireExpr<'_>, mut f: F)
417	    where
418	        F: FnMut(&mut Tables, Arc<Resource>),
419	    {
420	        let rtables = self.tables.tables.read().unwrap();
421	        let Some(mut prefix) = rtables
422	            .data
423	            .get_mapping(&self.state, &expr.scope, expr.mapping)
424	            .cloned()
425	        else {
426	            tracing::error!(?expr.scope, ?expr.mapping, "Unknown wire expr");
427	            return;
428	        };
429	
430	        let (res, mut wtables) = if let Some(res) =
431	            Resource::get_resource(&prefix, &expr.suffix).filter(|r| r.ctx.is_some())
432	        {
433	            drop(rtables);
434	            (res, self.tables.tables.write().unwrap())
435	        } else {
436	            let mut fullexpr = prefix.expr().to_string();
437	            fullexpr.push_str(expr.suffix.as_ref());
438	            let mut matches = keyexpr::new(fullexpr.as_str())
439	                .map(|ke| Resource::get_matches(&rtables.data, ke))
440	                .unwrap_or_default();
441	            drop(rtables);
442	            let mut wtables = self.tables.tables.write().unwrap();
443	            let tables = &mut *wtables;
444	            let mut res = Resource::make_resource(tables, &mut prefix, expr.suffix.as_ref());
445	            matches.push(Arc::downgrade(&res));
446	            Resource::match_resource(&tables.data, &mut res, matches);
447	            (res, wtables)
448	        };
449	
450	        tracing::debug!(?expr, expr.mapped = ?res);
451	
452	        let tables = &mut *wtables;
453	        f(tables, res)
454	
455	        // wtables is dropped
456	    }
457	
458	    /// Like [`Face::with_mapped_expr`], but `expr` may be absent.
459	    ///
460	    /// If `expr` is `Some`, resolves it to a resource (creating it if needed) and calls
461	    /// `f(tables, Some(resource))`.  If `expr` is `None`, acquires the write lock and calls
462	    /// `f(tables, None)` directly.
463	    pub(crate) fn with_mapped_optional_expr<F>(&self, expr: Option<&WireExpr<'_>>, mut f: F)
464	    where
465	        F: FnMut(&mut Tables, Option<Arc<Resource>>),
466	    {
467	        match expr {
468	            Some(expr) => self.with_mapped_expr(expr, |tables, res| f(tables, Some(res))),
469	            None => {
470	                let mut wtables = self.tables.tables.write().unwrap();
471	                let tables = &mut *wtables;
472	
473	                f(tables, None)
474	
475	                // wtables is dropped
476	            }
477	        }
478	    }
479	
480	    /// Like [`Face::with_mapped_expr`], but `expr` may be empty (as in undeclare messages).
481	    ///
482	    /// If `expr` is non-empty, looks up the resource and calls `f(tables, Some(resource))`.
483	    /// If `expr` is empty, acquires the write lock and calls `f(tables, None)`.
484	    /// Returns early without calling `f` if the mapping is unknown.
485	    ///
486	    /// When `make_if_unknown` is `false`, the resource must already exist; returns early if not
487	    /// found.  When `true`, an unknown resource is created (and matched) before calling `f`.
488	    pub(crate) fn with_mapped_nullable_expr<F>(
489	        &self,
490	        expr: &WireExpr<'_>,
491	        make_if_unknown: bool,
492	        mut f: F,
493	    ) where
494	        F: FnMut(&mut Tables, Option<Arc<Resource>>),
495	    {
496	        let (res, mut wtables) = if !expr.is_empty() {
497	            let rtables = self.tables.tables.read().unwrap();
498	
499	            let Some(mut prefix) = rtables
500	                .data
501	                .get_mapping(&self.state, &expr.scope, expr.mapping)
502	                .cloned()
503	            else {
504	                tracing::error!(?expr.scope, ?expr.mapping, "Unknown wire expr");
505	                return;
506	            };
507	
508	            // NOTE(regions): this block differs from `with_mapped_expr` in that (1) is doesn't
509	            // check `Resource::ctx` and (2) doesn't unconditionally make unknown resources.
510	            if let Some(res) = Resource::get_resource(&prefix, &expr.suffix) {
511	                drop(rtables);
512	                (Some(res), self.tables.tables.write().unwrap())
513	            } else if make_if_unknown {
514	                let mut fullexpr = prefix.expr().to_string();
515	                fullexpr.push_str(expr.suffix.as_ref());
516	                let mut matches = keyexpr::new(fullexpr.as_str())
517	                    .map(|ke| Resource::get_matches(&rtables.data, ke))
518	                    .unwrap_or_default();
519	                drop(rtables);
520	                let mut wtables = self.tables.tables.write().unwrap();
521	                let mut res =
522	                    Resource::make_resource(&mut wtables, &mut prefix, expr.suffix.as_ref());
523	                matches.push(Arc::downgrade(&res));
524	                Resource::match_resource(&wtables.data, &mut res, matches);
525	                (Some(res), wtables)
526	            } else {
527	                tracing::error!(?prefix, suffix = ?expr.suffix, "Unknown resource");
528	                return;
529	            }
530	        } else {
531	            (None, self.tables.tables.write().unwrap())
532	        };
533	
534	        tracing::debug!(?expr, expr.mapped = ?res);
535	
536	        let tables = &mut *wtables;
537	
538	        f(tables, res)
539	
540	        // wtables is dropped
541	    }
542	}
543	
544	impl Primitives for Face {
545	    fn send_interest(&self, msg: &mut zenoh_protocol::network::Interest) {
546	        let ctrl_lock = zlock!(self.tables.ctrl_lock);
547	        if msg.mode != InterestMode::Final {
548	            let mut declares = vec![];
549	            self.interest(msg, &mut |p, m| declares.push((p.clone(), m)));
550	            drop(ctrl_lock);
551	            for (p, m) in declares {
552	                m.with_mut(|m| p.send_declare(m));
553	            }
554	        } else {
555	            self.interest_final(msg);
556	        }
557	    }
558	
559	    fn send_declare(&self, msg: &mut zenoh_protocol::network::Declare) {
560	        let ctrl_lock = zlock!(self.tables.ctrl_lock);
561	        match &mut msg.body {
562	            zenoh_protocol::network::DeclareBody::DeclareKeyExpr(m) => {
563	                register_expr(&self.tables, &mut self.state.clone(), m.id, &m.wire_expr);
564	            }
565	            zenoh_protocol::network::DeclareBody::UndeclareKeyExpr(m) => {
566	                unregister_expr(&self.tables, &mut self.state.clone(), m.id);
567	            }
568	            zenoh_protocol::network::DeclareBody::DeclareSubscriber(m) => {
569	                let mut declares = vec![];
570	                self.declare_subscriber(
571	                    m.id,
572	                    &m.wire_expr,
573	                    &SubscriberInfo,
574	                    msg.ext_nodeid.node_id,
575	                    &mut |p, m| declares.push((p.clone(), m)),
576	                );
577	                drop(ctrl_lock);
578	                for (p, m) in declares {
579	                    m.with_mut(|m| p.send_declare(m));
580	                }
581	            }
582	            zenoh_protocol::network::DeclareBody::UndeclareSubscriber(m) => {
583	                let mut declares = vec![];
584	                self.undeclare_subscriber(
585	                    m.id,
586	                    &m.ext_wire_expr.wire_expr,
587	                    msg.ext_nodeid.node_id,
588	                    &mut |p, m| declares.push((p.clone(), m)),
589	                );
590	                drop(ctrl_lock);
591	                for (p, m) in declares {
592	                    m.with_mut(|m| p.send_declare(m));
593	                }
594	            }
595	            zenoh_protocol::network::DeclareBody::DeclareQueryable(m) => {
596	                let mut declares = vec![];
597	                self.declare_queryable(
598	                    m.id,
599	                    &m.wire_expr,
600	                    &m.ext_info,
601	                    msg.ext_nodeid.node_id,
602	                    &mut |p, m| declares.push((p.clone(), m)),
603	                );
604	                drop(ctrl_lock);
605	                for (p, m) in declares {
606	                    m.with_mut(|m| p.send_declare(m));
607	                }
608	            }
609	            zenoh_protocol::network::DeclareBody::UndeclareQueryable(m) => {
610	                let mut declares = vec![];
611	                self.undeclare_queryable(
612	                    m.id,
613	                    &m.ext_wire_expr.wire_expr,
614	                    msg.ext_nodeid.node_id,
615	                    &mut |p, m| declares.push((p.clone(), m)),
616	                );
617	                drop(ctrl_lock);
618	                for (p, m) in declares {
619	                    m.with_mut(|m| p.send_declare(m));
620	                }
621	            }
622	            zenoh_protocol::network::DeclareBody::DeclareToken(m) => {
623	                let mut declares = vec![];
624	                self.declare_token(
625	                    m.id,
626	                    &m.wire_expr,
627	                    msg.ext_nodeid.node_id,
628	                    msg.interest_id,
629	                    &mut |p, m| declares.push((p.clone(), m)),
630	                );
631	                drop(ctrl_lock);
632	                for (p, m) in declares {
633	                    m.with_mut(|m| p.send_declare(m));
634	                }
635	            }
636	            zenoh_protocol::network::DeclareBody::UndeclareToken(m) => {
637	                let mut declares = vec![];
638	                self.undeclare_token(
639	                    m.id,
640	                    &m.ext_wire_expr,
641	                    msg.ext_nodeid.node_id,
642	                    &mut |p, m| declares.push((p.clone(), m)),
643	                );
644	                drop(ctrl_lock);
645	                for (p, m) in declares {
646	                    m.with_mut(|m| p.send_declare(m));
647	                }
648	            }
649	            zenoh_protocol::network::DeclareBody::DeclareFinal(_) => {
650	                let Some(id) = msg.interest_id else {
651	                    tracing::error!("Received DeclareFinal without interest id");
652	                    return;
653	                };
654	
655	                let mut wtables = zwrite!(self.tables.tables);
656	                let mut declares = vec![];
657	                self.declare_final(&mut wtables, id, msg.ext_nodeid.node_id, &mut |p, m| {
658	                    declares.push((p.clone(), m))
659	                });
660	
661	                drop(wtables);
662	                drop(ctrl_lock);
663	                for (p, m) in declares {
664	                    m.with_mut(|m| p.send_declare(m));
665	                }
666	            }
667	        }
668	    }
669	
670	    #[inline]
671	    fn send_push_consume(&self, msg: &mut Push, reliability: Reliability, consume: bool) {
672	        let _span = tracing::enabled!(tracing::Level::DEBUG).then(|| {
673	            tracing::debug_span!(
674	                "send_push",
675	                expr = %msg.wire_expr,
676	                is_reliable = bool::from(reliability),
677	                consume,
678	            )
679	            .entered()
680	        });
681	
682	        route_data(&self.tables, &self.state, msg, reliability, consume);
683	    }
684	
685	    #[tracing::instrument(level = "debug", skip(msg), fields(id = msg.id, expr = %msg.wire_expr), ret)]
686	    fn send_request(&self, msg: &mut Request) {
687	        match msg.payload {
688	            RequestBody::Query(_) => {
689	                self.route_query(msg);
690	            }
691	        }
692	    }
693	
694	    #[tracing::instrument(level = "debug", skip(msg), fields(rid = msg.rid, expr = %msg.wire_expr), ret)]
695	    fn send_response(&self, msg: &mut Response) {
696	        route_send_response(&self.tables, &mut self.state.clone(), msg);
697	    }
698	
699	    #[tracing::instrument(level = "debug", skip(msg), fields(rid = msg.rid), ret)]
700	    fn send_response_final(&self, msg: &mut ResponseFinal) {
701	        route_send_response_final(&self.tables, &mut self.state.clone(), msg.rid);
702	    }
703	
704	    #[tracing::instrument(level = "debug", skip(self), fields(src = %self), ret)]
705	    fn send_close(&self) {
706	        let mut state = self.state.clone();
707	        state.task_controller.terminate_all(Duration::from_secs(10));
708	        finalize_pending_queries(&self.tables, &mut state);
709	        let mut declares = vec![];
710	        let ctrl_lock = zlock!(self.tables.ctrl_lock);
711	        finalize_pending_interests(&self.tables, &mut state, &mut |p, m| {
712	            declares.push((p.clone(), m))
713	        });
714	        let mut wtables = zwrite!(self.tables.tables);
715	        let tables = &mut *wtables;
716	
717	        let mut ctx = DispatcherContext {
718	            tables_lock: &self.tables,
719	            tables: &mut tables.data,
720	            src_face: &mut state,
721	            send_declare: &mut |p, m| declares.push((p.clone(), m)),
722	        };
723	
724	        let hats = &mut tables.hats;
725	        let region = self.state.region;
726	        let src_fid = ctx.src_face.id;
727	
728	        for mut res in hats[region].unregister_face_subscribers(ctx.reborrow()) {
729	            hats[region].disable_data_routes(&mut res);
730	
731	            let mut remaining = hats
732	                .values_mut()
733	                .filter(|hat| hat.remote_subscribers_of(ctx.tables, &res).is_some())
734	                .collect_vec();
735	
736	            if remaining.is_empty() {
737	                for hat in hats.values_mut() {
738	                    hat.unpropagate_subscriber(ctx.reborrow(), res.clone());
739	                }
740	                get_mut_unchecked(&mut res).face_ctxs.remove(&src_fid);
741	                Resource::clean(&mut res);
742	            } else if let [last_owner] = &mut *remaining {
743	                last_owner.unpropagate_last_non_owned_subscriber(ctx.reborrow(), res.clone())
744	            }
745	        }
746	
747	        for mut res in hats[region].unregister_face_queryables(ctx.reborrow()) {
748	            hats[region].disable_query_routes(&mut res);
749	
750	            let remaining = hats
751	                .iter()
752	                .filter_map(|(rgn, hat)| {
753	                    hat.remote_queryables_of(ctx.tables, &res)
754	                        .map(|info| (rgn, info))
755	                })
756	                .collect_vec();
757	
758	            match &*remaining {
759	                [] => {
760	                    for hat in hats.values_mut() {
761	                        hat.unpropagate_queryable(ctx.reborrow(), res.clone());
762	                    }
763	                    get_mut_unchecked(&mut res).face_ctxs.remove(&src_fid);
764	                    Resource::clean(&mut res);
765	                }
766	                [(last_owner, _)] if last_owner != &region => hats[last_owner]
767	                    .unpropagate_last_non_owned_queryable(ctx.reborrow(), res.clone()),
768	                _ => {
769	                    for hat in hats.values_mut() {
770	                        let other_info = remaining
771	                            .iter()
772	                            .filter_map(|(region, info)| (region != &hat.region()).then_some(*info))
773	                            .reduce(merge_qabl_infos);
774	
775	                        hat.propagate_queryable(ctx.reborrow(), res.clone(), other_info);
776	                    }
777	                }
778	            }
779	        }
780	
781	        for mut res in hats[region].unregister_face_tokens(ctx.reborrow()) {
782	            let mut remaining = hats
783	                .values_mut()
784	                .filter(|hat| hat.remote_tokens_of(ctx.tables, &res))
785	                .collect_vec();
786	
787	            if remaining.is_empty() {
788	                for hat in hats.values_mut() {
789	                    hat.unpropagate_token(ctx.reborrow(), res.clone());
790	                }
791	                get_mut_unchecked(&mut res).face_ctxs.remove(&src_fid);
792	                Resource::clean(&mut res);
793	            } else if let [last_owner] = &mut *remaining {
794	                last_owner.unpropagate_last_non_owned_token(ctx.reborrow(), res.clone())
795	            }
796	        }
797	
798	        for res in get_mut_unchecked(ctx.src_face).remote_mappings.values_mut() {
799	            get_mut_unchecked(res).face_ctxs.remove(&src_fid);
800	            Resource::clean(res);
801	        }
802	        get_mut_unchecked(ctx.src_face).remote_mappings.clear();
803	
804	        for res in get_mut_unchecked(ctx.src_face).local_mappings.values_mut() {
805	            get_mut_unchecked(res).face_ctxs.remove(&src_fid);
806	            Resource::clean(res);
807	        }
808	        get_mut_unchecked(ctx.src_face).local_mappings.clear();
809	
810	        for interest in get_mut_unchecked(ctx.src_face).local_interests.values_mut() {
811	            if let Some(mut res) = interest.res.take() {
812	                Resource::clean(&mut res);
813	            }
814	        }
815	        get_mut_unchecked(ctx.src_face).local_interests.clear();
816	
817	        hats[region].close_face(ctx);
818	
819	        tables.data.faces.remove(&src_fid);
820	
821	        drop(wtables);
822	        drop(ctrl_lock);
823	        for (p, m) in declares {
824	            m.with_mut(|m| p.send_declare(m));
825	        }
826	    }
827	
828	    fn as_any(&self) -> &dyn Any {
829	        self
830	    }
831	}
